import './App.css';
import React, {useEffect, useState} from "react";
import Axios from "axios";
import styles from "./styles.module.css";
import 'react-edit-text/dist/index.css';

function App() {
    const [listOfBooks, setListOfBooks] = useState([]);
    const [title, setTitle] = useState("");
    const [author, setAuthor] = useState("");
    const [year, setYear] = useState(0);
    const [color, setColor] = useState("");

    async function fetchData() {
        const response = await Axios.get(process.env.REACT_APP_HOST_LINK + "/getBooks");
        setListOfBooks(response.data)
    }

    useEffect(() => {
        fetchData();
    }, []);


    const createBook = () => {
        if ((color.match(/^#[0-9a-f]{3}(?:[0-9a-f]{3})?$/i))) {
        Axios.post(process.env.REACT_APP_HOST_LINK + "/createBook", {
            title, author, year, color
        }).then(() => {
            fetchData();
        });
    } else {
            alert("Incorrect input")
        }};


    const deleteBook = (id) => {
        Axios.delete(`http://localhost:3000/deleteBook/${id}`)
            .then((id) => {
                console.log(id);
                fetchData();
            });
    };

    const clearBooks = () => {
        Axios.delete("http://localhost:3000/clearBooks/")
            .then((response) => {
                console.log(response);
                fetchData();
            });
    };

    const updateBook = (id, newBookAuthor, newBookTitle, newBookYear, newBookColor) => {
        console.log(newBookAuthor, newBookTitle, newBookYear, newBookColor)
        Axios.put("http://localhost:3000/updateBook/", {
            id: id,
            author: newBookAuthor,
            title: newBookTitle,
            year: parseInt(newBookYear),
            color: newBookColor
        })
            .then((response) => {
                console.log(response);
                fetchData();
            });
    };


    return (<div className="App">
        <div className="booksDisplay">
            {listOfBooks.map((book) => {

                return (<div className={styles.booksParent}>
                    <h1 className={styles.title} style={{backgroundColor: book.color}}> {book.title}</h1>
                    <h1 className={styles.title} style={{backgroundColor: book.color}}>{book.author}</h1>
                    <h1 className={styles.title} style={{backgroundColor: book.color}}>{book.year}</h1>
                    <button onClick={() => {
                        const newBookTitle = prompt('Input a change you want to make to the title.');
                        const newBookAuthor = prompt('Input a change you want to make to the author.');
                        const newBookYear = prompt('Input a change you want to make to the year.');
                        const newBookColor = prompt('Input a change you want to make to the color.');
                        console.log(newBookColor)
                        if (newBookAuthor || newBookTitle || newBookYear || (newBookColor.match(/^#[0-9a-f]{3}(?:[0-9a-f]{3})?$/i))) {
                            console.log("updating in progress or something")
                            updateBook(book._id, newBookAuthor, newBookTitle, newBookYear, newBookColor)
                        } else {
                            alert("Please enter something.")
                        }
                    }}> Update
                    </button>
                    <button onClick={() => {
                        if (window.confirm('Delete?')) {
                                deleteBook(book._id)
                        }
                    }}> Delete
                    </button>
                </div>)
            })}

        </div>
        <div>
            <input
                type="text"
                placeholder="Title"
                onChange={(event) => {
                    setTitle(event.target.value);
                }}
            />
            <input
                type="text"
                placeholder="Author"
                onChange={(event) => {
                    setAuthor(event.target.value);
                }}
            />
            <input
                type="number"
                placeholder="Year"
                onChange={(event) => {
                    setYear(event.target.value);
                }}
            />
            <input
                type="text"
                placeholder="Hex Color"
                onChange={(event) => {
                    setColor(event.target.value);
                }}
            />
            <button onClick={createBook}> Create Book</button>
            <button onClick={() => {
                if (window.confirm('Clear?')) {
                    clearBooks();
                }
            }}> Clear Books
            </button>
        </div>
    </div>);

}

export default App;
